// heatmap.js 2.0.5 在严格 ESM 中会给只读 ImageData.data 重新赋值;调用期间让 getImageData 返回可写 data 并立即恢复
import h337 from 'https://cdn.jsdelivr.net/npm/heatmap.js@2.0.5/+esm';
const el = document.getElementById('heatmap'); el.style.position = 'relative'; el.style.width = '600px'; el.style.height = '400px';
const hm = h337.create({ container: el, radius: data.config?.radius ?? 40, maxOpacity: data.config?.maxOpacity ?? 1, minOpacity: data.config?.minOpacity ?? 0, blur: data.config?.blur ?? 0.85, gradient: data.config?.gradient });
const originalGetImageData = CanvasRenderingContext2D.prototype.getImageData;
CanvasRenderingContext2D.prototype.getImageData = function (...args) { const image = originalGetImageData.apply(this, args); const descriptor = Object.getOwnPropertyDescriptor(image, 'data'); if (descriptor && !descriptor.writable) Object.defineProperty(image, 'data', { ...descriptor, writable:true }); return image; };
try { hm.setData({ max: data.max ?? Math.max(...data.points.map(p => p.value)), min: data.min ?? 0, data: data.points }); }
finally { CanvasRenderingContext2D.prototype.getImageData = originalGetImageData; }

